import React, {Component} from 'react';
import ReactDOM from 'react-dom';
import {TreeCanvas} from 'butterfly-dag';

import mockData from './data';

import 'butterfly-dag/dist/index.css';
import './index.less';

class CompactBoxTree extends Component {
  componentDidMount() {
    let root = document.getElementById('dag-canvas');
    this.canvas = new TreeCanvas({
      root: root,
      disLinkable: true, // 可删除连线
      linkable: true,    // 可连线
      draggable: true,   // 可拖动
      zoomable: true,    // 可放大
      moveable: true,    // 可平移
      theme: {
        edge: {
          shapeType: 'Manhattan',
          arrow: true
        }
      },
      layout: {
        type: 'compactBox',
        options: {
          direction: 'TB',
          getHeight(d) {
            return 60;
          },
          getWidth(d) {
            return 120;
          },
          getHGap(d) {
            return 20;
          },
          getVGap(d) {
            return 80;
          },
        }
      }
    });

    this.canvas.draw(mockData, {}, () => {
      this.canvas.focusCenterWithAnimate();
    });
  }

  render() {
    return (
      <div className='compact-box-tree-page'>
        <div className="compact-box-tree-canvas" id="dag-canvas">
        </div>
      </div>
    );
  }
}

ReactDOM.render(<CompactBoxTree />, document.getElementById('root'));

import $ from 'jquery';
import {TreeNode} from 'butterfly-dag';

import './node.less';

class BaseNode extends TreeNode {
  draw = (opts) => {
    let container = $('<div class="iot-node"></div>')
      .css('top', opts.top + 'px')
      .css('left', opts.left + 'px')
      .attr('id', opts.id);

    let titleDom = $(`<div class="title ${opts.options.color}"><i class="iconfont ${opts.options.iconType} ${opts.options.iconClass}"></i>${opts.options.title}<div>`);
    let contentDom = $(`<div class="content">${opts.options.content}<div>`);

    container.append(titleDom);
    container.append(contentDom);
    this.showExpandBtn(container);
    return container[0];
  }
  showExpandBtn(container = this.dom) {
    let expandBtn = $(`<div class='expand-btn'>···</div>`);
    expandBtn.on('click', (e) => {
      e.stopPropagation();
      e.preventDefault();
      if (this.collapsed) {
        // 可以在这里向后端请求数据,把node穿进去expand里面
        this.expand();
      } else {
        this.collapse();
      }
    });
    expandBtn.appendTo(container);
  }
}

export default BaseNode;

@import 'theme.less'; 


.iot-node {
  position: absolute;
  width: 110px;
  height: 64px;
  .title {
    height: 28px;
    line-height: 28px;
    color: @butterfly-overlay-font-color;
    padding: 0 5px;
    border-radius: 8.04px 8.04px 0 0;
    border:@butterfly-box-border;
    background: @butterfly-primary-color;
    .icon-class {
      vertical-align: bottom;
      margin-right: 5px;
    }
  }
  .content {
    height: 32px;
    line-height: 32px;
    padding: 0 8px;
    border:@butterfly-box-border;
    background: @butterfly-theme-color;
    border-radius: 0 0 8.04px 8.04px;
    font-size: 12px;
    color: @butterfly-normal-font-color;
    text-align: center;
  }
  .expand-btn {
    position: absolute;
    bottom: -17px;
    left: 46px;
    height: 10px;
    width: 20px;
    line-height: 8px;
    text-align: center;
    border-radius: 4px;
    border:@butterfly-box-border;
    box-shadow:@butterfly-box-shadow;
    background: @butterfly-theme-color;
    cursor: pointer;
  }
  .expand-btn:hover{
    border:@butterfly-box-node-border-hover;
    border-radius: 5px;
  }
}

